def validate(args, output):
    nums = args[0]
    if not isinstance(output, list):
        return False
    from collections import Counter
    avail = Counter(nums)
    seen = set()
    for sub in output:
        if not isinstance(sub, list):
            return False
        c = Counter(sub)
        for v, k in c.items():
            if avail.get(v, 0) < k:
                return False
        key = tuple(sorted(sub))
        if key in seen:
            return False
        seen.add(key)
    correct = set()
    items = sorted(avail.items())
    def build(i, cur):
        if i == len(items):
            correct.add(tuple(cur))
            return
        v, cnt = items[i]
        for take in range(cnt + 1):
            build(i + 1, cur + [v] * take)
    build(0, [])
    return seen == correct

