function validate(args, output) {
    const nums = args[0];
    if (!Array.isArray(output)) return false;
    const counts = function(arr) {
        const m = new Map();
        for (const v of arr) m.set(v, (m.get(v) || 0) + 1);
        return m;
    };
    const avail = counts(nums);
    const seen = new Set();
    for (const sub of output) {
        if (!Array.isArray(sub)) return false;
        const c = counts(sub);
        for (const [v, k] of c) {
            if ((avail.get(v) || 0) < k) return false;
        }
        const key = sub.slice().sort((a, b) => a - b).join(',');
        if (seen.has(key)) return false;
        seen.add(key);
    }
    const correct = new Set();
    const items = Array.from(avail.entries()).sort((a, b) => a[0] - b[0]);
    const build = function(i, cur) {
        if (i === items.length) {
            correct.add(cur.join(','));
            return;
        }
        const [v, cnt] = items[i];
        for (let take = 0; take <= cnt; take++) {
            build(i + 1, cur.concat(new Array(take).fill(v)));
        }
    };
    build(0, []);
    if (seen.size !== correct.size) return false;
    for (const k of seen) if (!correct.has(k)) return false;
    return true;
}

