class Solution:
    def subsetsWithDup(self, nums):
        from itertools import combinations
        nums = sorted(nums)
        seen = set()
        res = []
        for r in range(len(nums) + 1):
            for combo in combinations(nums, r):
                if combo not in seen:
                    seen.add(combo)
                    res.append(list(combo))
        res.sort()
        return res

