class Solution:
    def subsetsWithDup(self, nums):
        nums = sorted(nums)
        res = []
        cur = []
        def back(start):
            res.append(cur[:])
            for i in range(start, len(nums)):
                if i > start and nums[i] == nums[i - 1]:
                    continue
                cur.append(nums[i])
                back(i + 1)
                cur.pop()
        back(0)
        for s in res:
            s.sort()
        res.sort()
        return res

